AOS.init({ once: true, offset: 50, duration: 1000 }); if (window.innerWidth >= 1024) { const cursor = document.getElementById('cursor'); const cursorDot = document.getElementById('cursor-dot'); document.addEventListener('mousemove', (e) => { cursorDot.style.left = e.clientX + 'px'; cursorDot.style.top = e.clientY + 'px'; setTimeout(() => { cursor.style.left = e.clientX + 'px'; cursor.style.top = e.clientY + 'px'; }, 40); }); document.querySelectorAll('a, button, input, textarea, .cursor-pointer, .popup-form label').forEach(el => { el.addEventListener('mouseenter', () => cursor.classList.add('hover')); el.addEventListener('mouseleave', () => cursor.classList.remove('hover')); }); } const popup = document.getElementById('popup-captura'); function abrirPopup() { popup.classList.remove('hidden'); popup.classList.add('flex'); document.body.style.overflow = 'hidden'; setTimeout(() => document.getElementById('lead-nome').focus(), 300); } function fecharPopup() { popup.classList.add('hidden'); popup.classList.remove('flex'); document.body.style.overflow = ''; } popup.addEventListener('click', (e) => { if (e.target === popup) fecharPopup(); }); document.addEventListener('keydown', (e) => { if (e.key === 'Escape') fecharPopup(); }); const telInput = document.getElementById('lead-phone'); telInput.addEventListener('input', function(e) { let value = e.target.value.replace(/\D/g, ''); if (value.startsWith('55') && value.length > 2) value = value.slice(2); value = value.slice(0, 11); let formatado = value; if (value.length > 2) { formatado = `(${value.slice(0, 2)}) ` + value.slice(2); } if (value.length > 7) { formatado = formatado.slice(0, 10) + '-' + formatado.slice(10); } e.target.value = formatado; const errorMsg = document.querySelector('.error-msg'); if (errorMsg) errorMsg.classList.add('hidden'); }); function obterUTMs() { const params = new URLSearchParams(window.location.search); return { utm_source: params.get('utm_source') || '', utm_medium: params.get('utm_medium') || '', utm_campaign: params.get('utm_campaign') || '', utm_term: params.get('utm_term') || '', utm_content: params.get('utm_content') || '' }; } const form = document.getElementById('form-consultoria-premium'); form.addEventListener('submit', async function(e) { e.preventDefault(); const btnSubmit = this.querySelector('.btn-submit'); const errorMsg = this.querySelector('.error-msg'); const rawPhone = telInput.value.replace(/\D/g, ''); if (rawPhone.length < 10) { errorMsg.classList.remove('hidden'); telInput.focus(); return; } btnSubmit.disabled = true; btnSubmit.innerHTML = '<i class="fas fa-spinner fa-spin mr-2"></i> Processando...'; const nome = document.getElementById('lead-nome').value.trim(); const email = document.getElementById('lead-email').value.trim(); const telefoneFormatado = '+55' + rawPhone; const urlAtual = window.location.href.split('?')[0]; const utms = obterUTMs(); const payload = { nome: nome, email: email, telefone: telefoneFormatado, utm_source: utms.utm_source, utm_medium: utms.utm_medium, utm_campaign: utms.utm_campaign, utm_term: utms.utm_term, utm_content: utms.utm_content, url: urlAtual, produto: "DO ZERO À CONSULTORIA ONLINE" }; const WEBHOOK_URL = 'https://hook.us1.make.com/4n42ngpte48fu0mvpnh5ewi4vu3ddah4'; const BASE_REDIRECT_URL = urlAtual; try { const response = await fetch(WEBHOOK_URL, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) }); if (!response.ok) { console.error("Webhook recusado."); } } catch (error) { console.error("Erro ao enviar dados para o webhook:", error); } finally { const queryString = `?sucesso=true&name=${encodeURIComponent(nome)}&email=${encodeURIComponent(email)}&phone=${encodeURIComponent(telefoneFormatado)}&utm_source=${encodeURIComponent(utms.utm_source)}&utm_term=${encodeURIComponent(utms.utm_term)}&utm_campaign=${encodeURIComponent(utms.utm_campaign)}&utm_medium=${encodeURIComponent(utms.utm_medium)}&utm_content=${encodeURIComponent(utms.utm_content)}`; window.location.href = BASE_REDIRECT_URL + queryString; } }); window.onload = function() { const params = new URLSearchParams(window.location.search); if(params.get('sucesso') === 'true') { alert("Obrigado pela sua inscrição no Workshop! Você será contatado em breve para finalizar sua participação."); } }